type UpdatePostBody = {
  title?: string;
  content?: string;
};

type RouteParams = {
  id: string;
};

export async function GET(_request: Request, { params }: { params: Promise<RouteParams> }) {
  const { id } = await params;
  const numericId = Number.parseInt(id, 10);

  const post = {
    id: numericId,
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return Response.json(post);
}

export async function PUT(request: Request, { params }: { params: Promise<RouteParams> }) {
  const { id } = await params;
  const numericId = Number.parseInt(id, 10);
  const body = (await request.json()) as UpdatePostBody;

  const updatedPost = {
    id: numericId,
    title: body.title || `Post ${id}`,
    content: body.content || `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return Response.json(updatedPost);
}

export async function DELETE(_request: Request, { params }: { params: Promise<RouteParams> }) {
  const { id } = await params;

  return Response.json({ message: `Post ${id} deleted successfully` });
}
EOF

